-- Workday Board Tokens — 10132 company/site pairs
-- Source: github.com/Feashliaa/job-board-aggregator (CC BY-NC 4.0)
-- API pattern : POST https://{slug}.{wd}.myworkdayjobs.com/wday/cxs/{slug}/{site_id}/jobs
-- Board URL   : https://{slug}.{wd}.myworkdayjobs.com/en-US/{site_id}/jobs
--
-- Malformed entries (company_slug == wd_instance, e.g. wd1|wd1|...) are excluded.
-- Usage: Run once in Railway PostgreSQL console.
-- Status starts as 'UNKNOWN' — the handler validates on first run.

CREATE TABLE IF NOT EXISTS api.workday_board_tokens (
    id           SERIAL PRIMARY KEY,
    company_name VARCHAR(255) NOT NULL,
    company_slug VARCHAR(255) NOT NULL,
    wd_instance  VARCHAR(50)  NOT NULL,
    site_id      VARCHAR(255) NOT NULL,
    api_url      VARCHAR(600),
    board_url    VARCHAR(600),
    status       VARCHAR(50)  NOT NULL DEFAULT 'UNKNOWN',
    http_code    SMALLINT,
    job_count    INTEGER,
    industry     VARCHAR(255),
    created_at   TIMESTAMP    NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMP    NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_workday_slug_site UNIQUE (company_slug, site_id)
);

INSERT INTO api.workday_board_tokens
    (company_name, company_slug, wd_instance, site_id, api_url, board_url, status, created_at, updated_at)
SELECT
    INITCAP(REPLACE(REPLACE(v.slug, '-', ' '), '_', ' ')) AS company_name,
    v.slug,
    v.wd,
    v.site,
    v.api_url,
    v.board_url,
    'UNKNOWN',
    NOW(),
    NOW()
FROM (VALUES
